msg.query = "SELECT CODIGO, REPLACE(DENOMINACION, CHAR(13), '') AS NOMBRE, CUIT, SUBSTRING(MOMENTO,1,4)+'-'+SUBSTRING(MOMENTO,5,2)+'-'+SUBSTRING(MOMENTO,7,2) AS FECHA_ALTA FROM V_CLIENTE WHERE DENOMINACION IS NOT NULL AND DENOMINACION != '' ORDER BY CODIGO";
msg.topic = msg.query;
return msg;

var rows = msg.payload || [];
var csv = 'CODIGO,NOMBRE,CUIT,FECHA_ALTA\n';
rows.forEach(function(r) {
  csv += '"' + (r.CODIGO||'').trim() + '",';
  csv += '"' + (r.NOMBRE||'').replace(/"/g,'""').trim() + '",';
  csv += '"' + (r.CUIT||'').trim() + '",';
  csv += '"' + (r.FECHA_ALTA||'').trim() + '"\n';
});
msg.payload = csv;
msg.headers = { 'Content-Type': 'text/csv; charset=utf-8', 'Content-Disposition': 'attachment; filename=clientes_calipso.csv' };
return msg;
